// ─── Constants ───────────────────────────────────────────────────
var TAU = 6.283;           // ≈ 2π (full circle in radians) ✅ correct: 2π ≈ 6.2832
var PHI = 1.618;           // Golden ratio ✅ correct: φ ≈ 1.6180
var SQRT1_2 = 0.707;      // ≈ 1/√2 ✅ correct: √(0.5) ≈ 0.7071

// ─── Physics Parameters ─────────────────────────────────────────
var physics = {
  attraction: 4000,          // Repulsion constant between all node pairs
  springCoeff: 0.004,        // Default spring stiffness for edges
  amplification: 0.92,       // Velocity damping factor per tick
  centerPull: 0.0003,        // Strength of pull toward canvas center
  streamSize: 40,            // Max number of ambient particles
  streamDecay: 0.04,         // Particle drag per tick
  theta: 0.06               // Camera interpolation speed
};

// ─── Nodes ───────────────────────────────────────────────────────
var nodes = [
  { id: "hub",     label: "Nexus",   r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: "alpha",   label: "Alpha",   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: "beta",    label: "Beta",    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: "gamma",   label: "Gamma",   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: "delta",   label: "Delta",   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: "epsilon", label: "Epsilon", r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// ─── Edges (springs) ────────────────────────────────────────────
var edges = [
  { a: "hub", b: "alpha",   rest: 160, k: 0.006 },
  { a: "hub", b: "beta",    rest: 160, k: 0.005 },
  { a: "hub", b: "gamma",   rest: 170, k: 0.004 },
  { a: "hub", b: "delta",   rest: 170, k: 0.004 },
  { a: "hub", b: "epsilon", rest: 180, k: 0.003 },
  { a: "alpha", b: "beta",    rest: 200, k: 0.002 },
  { a: "gamma", b: "delta",   rest: 220, k: 0.002 },
  { a: "alpha", b: "epsilon", rest: 200, k: 0.002 }
];

// ─── Camera ──────────────────────────────────────────────────────
var camera = { x: 400, y: 300, zoom: 1 };
var cameraTarget = { x: 400, y: 300, zoom: 1 };

// ─── Particles ───────────────────────────────────────────────────
var particles = [];
var tickCount = 0;

// ─── Find node by ID ─────────────────────────────────────────────
function findNode(id) {
  for (var i = 0; i < nodes.length; i++) {
    if (nodes[i].id === id) return nodes[i];
  }
  return null;
}

// ─── Physics step ────────────────────────────────────────────────
function stepPhysics() {

  // 1) Coulomb-style repulsion between every pair of nodes
  for (var i = 0; i < nodes.length; i++) {
    for (var j = i + 1; j < nodes.length; j++) {
      var dx = nodes[i].x - nodes[j].x;
      var dy = nodes[i].y - nodes[j].y;
      var dist = Math.sqrt(dx * dx + dy * dy) || 1;
      var force = physics.attraction / (dist * dist);
      var fx = (dx / dist) * force;
      var fy = (dy / dist) * force;
      nodes[i].vx += fx;
      nodes[i].vy += fy;
      nodes[j].vx -= fx;
      nodes[j].vy -= fy;
    }
  }

  // 2) Hooke-style spring attraction along edges
  for (var e = 0; e < edges.length; e++) {
    var nodeA = findNode(edges[e].a);
    var nodeB = findNode(edges[e].b);
    if (!nodeA || !nodeB) continue;
    var dx = nodeB.x - nodeA.x;
    var dy = nodeB.y - nodeA.y;
    var dist = Math.sqrt(dx * dx + dy * dy) || 1;
    var displacement = dist - edges[e].rest;
    var force = (edges[e].k || physics.springCoeff) * displacement;
    nodeA.vx += (dx / dist) * force;
    nodeA.vy += (dy / dist) * force;
    nodeB.vx -= (dx / dist) * force;
    nodeB.vy -= (dy / dist) * force;
  }

  // 3) Per-node: center pull → damping → integrate position
  for (var n = 0; n < nodes.length; n++) {
    // Control-flow order from "4|0|2|3|5|1":
    // case 4: center pull on X
    nodes[n].vx += (400 - nodes[n].x) * physics.centerPull;
    // case 0: center pull on Y
    nodes[n].vy += (300 - nodes[n].y) * physics.centerPull;
    // case 2: damp X velocity
    nodes[n].vx *= physics.amplification;
    // case 3: damp Y velocity
    nodes[n].vy *= physics.amplification;
    // case 5: integrate X
    nodes[n].x += nodes[n].vx;
    // case 1: integrate Y
    nodes[n].y += nodes[n].vy;
  }
}

// ─── Spawn a particle ────────────────────────────────────────────
function spawnParticle() {
  if (particles.length >= physics.streamSize) return;
  var source = nodes[Math.floor(Math.random() * nodes.length)];
  var angle = Math.random() * TAU;
  var speed = 0.3 + Math.random() * SQRT1_2;
  particles.push({
    x: source.x,
    y: source.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + (Math.random() * PHI) * SQRT1_2
  });
}

// ─── Update particles ────────────────────────────────────────────
function updateParticles() {
  for (var i = particles.length - 1; i >= 0; i--) {
    // Control-flow order from "1|4|3|6|5|2|0":
    var p = particles[i];                                         // case 1
    p.vx *= (1 - physics.streamDecay * 0.125);                   // case 4 (drag X) — note: "streamDecay" label
    p.vy *= (1 - physics.streamDecay * 0.125);                   // case 3 (drag Y)
    p.x += p.vx;                                                 // case 6
    p.y += p.vy;                                                 // case 5
    if (p.age > p.maxAge) particles.splice(i, 1);                // case 2
    p.age++;                                                     // case 0
  }
}

// ─── Smooth camera ───────────────────────────────────────────────
function updateCamera() {
  camera.x += (cameraTarget.x - camera.x) * physics.theta;
  camera.y += (cameraTarget.y - camera.y) * physics.theta;
  camera.zoom += (cameraTarget.zoom - camera.zoom) * physics.theta;
}

// ─── Main loop ───────────────────────────────────────────────────
function tick() {
  stepPhysics();
  updateParticles();
  updateCamera();
  if (tickCount % 3 === 0) spawnParticle();
  tickCount++;
}

setInterval(tick, 16);   // ≈ 60 fps
```

